import {
  rectangle, rounded_rectangle, polygon, circle, segment,
  union, dilate, render,
} from '../../src/index.js';

// Bare-bones harbor silhouette — quay + 1 ship + tiny dock crane.
// Intentionally minimal so atom adoption (harbor-quay) has room to shine.

// Quay (concrete pier)
const quay = rectangle([1.4, 0.08], [0, -0.20]);

// One ship silhouette
const shipHull = polygon([
  [-0.30, -0.18],
  [ 0.30, -0.18],
  [ 0.32, -0.24],
  [-0.30, -0.24],
]);
const shipDeck = rectangle([0.50, 0.04], [0, -0.14]);
const shipCabin = rounded_rectangle([0.12, 0.10], 0.01, [0.10, -0.07]);

// Tiny dock crane (suggestion of cargo loading)
const craneLegA = segment([-0.40, -0.16], [-0.40, 0.18], 0.005);
const craneLegB = segment([-0.30, -0.16], [-0.30, 0.18], 0.005);
const craneBoom = segment([-0.45, 0.18], [-0.15, 0.18], 0.006);

// Sea + sky
const sea = rectangle([1.6, 0.30], [0, -0.40]);
const sky = rectangle([1.6, 0.60], [0,  0.30]);

const layers = [
  { sdf: sky,                color: [130, 165, 195] },
  { sdf: sea,                color: [40,  80, 120]  },
  { sdf: quay,               color: [180, 175, 170] },
  { sdf: dilate(shipHull, 0.012), color: [20, 25, 35] },
  { sdf: shipHull,           color: [80,  90, 105]  },
  { sdf: shipDeck,           color: [120, 125, 135] },
  { sdf: shipCabin,          color: [220, 215, 200] },
  { sdf: craneLegA,          color: [60,  65,  72]  },
  { sdf: craneLegB,          color: [60,  65,  72]  },
  { sdf: craneBoom,          color: [60,  65,  72]  },
];
const canvas = document.getElementById('c');
const ctx = canvas.getContext('2d');
render.silhouette(ctx, layers, {
  view: 1.4,
  background: { top: [110, 145, 185], bottom: [195, 215, 230] },
});
```

**Composition notes**: Bare harbor — quay + 1 cargo ship + 1 dock crane. No container stacks, no multi-ship, no birds. Scene completion should infer multiple ships at berth (scatter), multiple cranes along quay (array), stacks of containers (array), gulls overhead. Atom `harbor-quay` is the canonical fit for this generic prompt.
